from __future__ import annotations

from dataclasses import dataclass, replace
from datetime import datetime, timezone
from enum import Enum
from heapq import heappop, heappush
from itertools import count
from types import TracebackType
from typing import Generic, Iterable, Iterator, TypeAlias, TypeVar
from uuid import UUID, uuid4


T = TypeVar("T")
TaskId: TypeAlias = UUID | str
HeapEntry: TypeAlias = tuple[int, int, int, UUID]


class PriorityTaskQueueError(Exception):
    """Base exception for PriorityTaskQueue errors."""


class EmptyQueueError(PriorityTaskQueueError):
    """Raised when attempting to read from an empty queue."""


class TaskNotFoundError(PriorityTaskQueueError):
    """Raised when a task ID does not identify a queued task."""


class TaskStatus(str, Enum):
    """Lifecycle state of a task."""

    QUEUED = "queued"
    DEQUEUED = "dequeued"
    CANCELLED = "cancelled"


@dataclass(frozen=True, slots=True)
class Task(Generic[T]):
    """Immutable task record managed by PriorityTaskQueue."""

    id: UUID
    payload: T
    priority: int
    created_at: datetime
    status: TaskStatus = TaskStatus.QUEUED


class PriorityTaskQueue(Generic[T]):
    """A max-priority FIFO-stable task queue.

    Higher numeric priority values are dequeued first. Tasks with the same
    priority are dequeued in the order they were added to the queue.
    """

    def __init__(self, initial_tasks: Iterable[tuple[T, int]] | None = None) -> None:
        """Create an empty queue, optionally seeded with payload/priority pairs."""
        self._heap: list[HeapEntry] = []
        self._tasks: dict[UUID, Task[T]] = {}
        self._sequence_by_id: dict[UUID, int] = {}
        self._version_by_id: dict[UUID, int] = {}
        self._sequence = count()

        if initial_tasks is not None:
            for payload, priority in initial_tasks:
                self.add_task(payload, priority)

    def add_task(self, payload: T, priority: int) -> Task[T]:
        """Add a task and return its generated Task record."""
        self._validate_priority(priority)

        task_id = uuid4()
        while task_id in self._tasks:
            task_id = uuid4()

        task = Task(
            id=task_id,
            payload=payload,
            priority=priority,
            created_at=datetime.now(timezone.utc),
        )

        self._tasks[task.id] = task
        self._sequence_by_id[task.id] = next(self._sequence)
        self._version_by_id[task.id] = 0
        self._push_current_task(task.id)

        return task

    def get_next_task(self) -> Task[T]:
        """Remove and return the next highest-priority task.

        Raises:
            EmptyQueueError: If the queue has no tasks.
        """
        self._discard_stale_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot get the next task from an empty queue.")

        _, _, _, task_id = heappop(self._heap)
        task = self._tasks.pop(task_id)

        self._sequence_by_id.pop(task_id, None)
        self._version_by_id.pop(task_id, None)

        return replace(task, status=TaskStatus.DEQUEUED)

    def peek_next_task(self) -> Task[T]:
        """Return the next highest-priority task without removing it.

        Raises:
            EmptyQueueError: If the queue has no tasks.
        """
        self._discard_stale_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot peek at an empty queue.")

        return self._tasks[self._heap[0][3]]

    def get_task(self, task_id: TaskId) -> Task[T]:
        """Return a queued task by ID.

        Raises:
            TaskNotFoundError: If the task is not currently queued.
        """
        _, task = self._get_queued_task(task_id)
        return task

    def cancel_task(self, task_id: TaskId) -> Task[T]:
        """Remove a queued task by ID and return it with CANCELLED status.

        Raises:
            TaskNotFoundError: If the task is not currently queued.
        """
        normalized_id, task = self._get_queued_task(task_id)

        self._tasks.pop(normalized_id)
        self._sequence_by_id.pop(normalized_id, None)
        self._version_by_id.pop(normalized_id, None)

        return replace(task, status=TaskStatus.CANCELLED)

    def remove_task(self, task_id: TaskId) -> Task[T]:
        """Remove a queued task by ID.

        This is an alias for cancel_task().
        """
        return self.cancel_task(task_id)

    def update_task_priority(self, task_id: TaskId, priority: int) -> Task[T]:
        """Update a queued task's priority and return the updated Task record.

        The task keeps its original FIFO position among tasks with the same
        priority.

        Raises:
            TaskNotFoundError: If the task is not currently queued.
        """
        self._validate_priority(priority)

        normalized_id, task = self._get_queued_task(task_id)

        if task.priority == priority:
            return task

        updated_task = replace(task, priority=priority)

        self._tasks[normalized_id] = updated_task
        self._version_by_id[normalized_id] += 1
        self._push_current_task(normalized_id)

        return updated_task

    def list_tasks(self, *, priority: int | None = None) -> tuple[Task[T], ...]:
        """Return queued tasks in priority order, optionally filtered by priority."""
        if priority is not None:
            self._validate_priority(priority)

        return self._ordered_tasks(priority=priority)

    def tasks_with_priority(self, priority: int) -> tuple[Task[T], ...]:
        """Return queued tasks with the given priority, in FIFO order."""
        return self.list_tasks(priority=priority)

    def priority_levels(self) -> tuple[int, ...]:
        """Return active priority levels from highest to lowest."""
        return tuple(sorted({task.priority for task in self._tasks.values()}, reverse=True))

    @property
    def size(self) -> int:
        """Return the number of queued tasks."""
        return len(self)

    def is_empty(self) -> bool:
        """Return True when the queue has no tasks."""
        return len(self) == 0

    def clear(self) -> None:
        """Remove all queued tasks."""
        self._heap.clear()
        self._tasks.clear()
        self._sequence_by_id.clear()
        self._version_by_id.clear()
        self._sequence = count()

    def __len__(self) -> int:
        """Return the number of queued tasks."""
        return len(self._tasks)

    def __bool__(self) -> bool:
        """Return True when the queue contains at least one task."""
        return not self.is_empty()

    def __iter__(self) -> Iterator[Task[T]]:
        """Iterate over queued tasks in priority order without removing them."""
        return iter(self.list_tasks())

    def __repr__(self) -> str:
        """Return a compact developer-friendly representation."""
        return (
            f"{type(self).__name__}"
            f"(size={self.size}, priority_levels={list(self.priority_levels())!r})"
        )

    def __enter__(self) -> PriorityTaskQueue[T]:
        """Enter a context manager block and return this queue."""
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None,
        exc: BaseException | None,
        traceback: TracebackType | None,
    ) -> bool:
        """Clear queued tasks when leaving a context manager block."""
        self.clear()
        return False

    def _push_current_task(self, task_id: UUID) -> None:
        """Push the current version of a queued task onto the heap."""
        task = self._tasks[task_id]
        sequence = self._sequence_by_id[task_id]
        version = self._version_by_id[task_id]

        heappush(self._heap, (-task.priority, sequence, version, task.id))

    def _discard_stale_entries(self) -> None:
        """Remove heap entries for cancelled, dequeued, or reprioritized tasks."""
        while self._heap and not self._is_current_heap_entry(self._heap[0]):
            heappop(self._heap)

    def _is_current_heap_entry(self, entry: HeapEntry) -> bool:
        """Return True if a heap entry matches the current queued task state."""
        negative_priority, sequence, version, task_id = entry
        task = self._tasks.get(task_id)

        return (
            task is not None
            and task.priority == -negative_priority
            and self._sequence_by_id.get(task_id) == sequence
            and self._version_by_id.get(task_id) == version
        )

    def _ordered_tasks(self, *, priority: int | None = None) -> tuple[Task[T], ...]:
        """Return a snapshot of queued tasks ordered by dequeue order."""
        tasks = self._tasks.values()

        if priority is not None:
            tasks = (task for task in tasks if task.priority == priority)

        return tuple(
            sorted(
                tasks,
                key=lambda task: (-task.priority, self._sequence_by_id[task.id]),
            )
        )

    def _get_queued_task(self, task_id: TaskId) -> tuple[UUID, Task[T]]:
        """Return a normalized UUID and queued task or raise TaskNotFoundError."""
        normalized_id = self._normalize_task_id(task_id)

        try:
            return normalized_id, self._tasks[normalized_id]
        except KeyError:
            raise TaskNotFoundError(
                f"No queued task found with id {normalized_id}."
            ) from None

    @staticmethod
    def _normalize_task_id(task_id: TaskId) -> UUID:
        """Normalize a UUID or UUID string into a UUID instance."""
        if isinstance(task_id, UUID):
            return task_id

        if isinstance(task_id, str):
            try:
                return UUID(task_id)
            except ValueError:
                raise TaskNotFoundError(
                    f"No queued task found with id {task_id!r}."
                ) from None

        raise TypeError("task_id must be a UUID or UUID string.")

    @staticmethod
    def _validate_priority(priority: int) -> None:
        """Validate that priority is an integer level."""
        if not isinstance(priority, int) or isinstance(priority, bool):
            raise TypeError("priority must be an integer.")
